module multi_pipe_8bit (
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out
);
    reg mul_en_out_reg;
    reg [7:0] mul_a_reg;
    reg [7:0] mul_b_reg;
    wire [15:0] temp [7:0];
    reg [15:0] sum [7:0];
    assign mul_en_out = mul_en_out_reg;
    assign mul_out = sum[7];
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_en_out_reg <= 1'b0;
            mul_a_reg <= 8'b0;
            mul_b_reg <= 8'b0;
        end else begin
            mul_en_out_reg <= mul_en_in;
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end
    assign temp[0] = mul_en_out_reg ? {8'b0, mul_a_reg[0] & mul_b_reg[0]} : 16'b0;
    assign temp[1] = mul_en_out_reg ? {7'b0, mul_a_reg[1] & mul_b_reg[0], 1'b0} : 16'b0;
    assign temp[2] = mul_en_out_reg ? {6'b0, mul_a_reg[2] & mul_b_reg[0], 2'b0} : 16'b0;
    assign temp[3] = mul_en_out_reg ? {5'b0, mul_a_reg[3] & mul_b_reg[0], 3'b0} : 16'b0;
    assign temp[4] = mul_en_out_reg ? {4'b0, mul_a_reg[4] & mul_b_reg[0], 4'b0} : 16'b0;
    assign temp[5] = mul_en_out_reg ? {3'b0, mul_a_reg[5] & mul_b_reg[0], 5'b0} : 16'b0;
    assign temp[6] = mul_en_out_reg ? {2'b0, mul_a_reg[6] & mul_b_reg[0], 6'b0} : 16'b0;
    assign temp[7] = mul_en_out_reg ? {1'b0, mul_a_reg[7] & mul_b_reg[0], 7'b0} : 16'b0;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum[0] <= 16'b0;
            sum[1] <= 16'b0;
            sum[2] <= 16'b0;
            sum[3] <= 16'b0;
            sum[4] <= 16'b0;
            sum[5] <= 16'b0;
            sum[6] <= 16'b0;
            sum[7] <= 16'b0;
        end else begin
            sum[0] <= temp[0];
            sum[1] <= temp[1] + temp[2];
            sum[2] <= temp[3] + temp[4];
            sum[3] <= temp[5] + temp[6];
            sum[4] <= temp[7];
            sum[5] <= sum[1];
            sum[6] <= sum[2];
            sum[7] <= sum[3];
        end
    end
endmodule
